import java.util.Scanner;

public class BufferOverflowFixed {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine(); // Read entire line

        char[] buffer = new char[10];

        // Copy userInput into buffer with proper length checking
        int lengthToCopy = Math.min(userInput.length(), buffer.length);
        for (int i = 0; i < lengthToCopy; i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
